#include <stdio.h>
#include <stdint.h>

/* Function to print an 8-bit integer in binary format for educational inspection */
void print_binary8(uint8_t value) {
    for (int i = 7; i >= 0; i--) {
        printf("%d", (value >> i) & 1);
    }
    printf("\n");
}

int main(void) {
    uint8_t reg = 0x00; /* Register starting at 00000000 */
    printf("Initial register state:      ");
    print_binary8(reg);

    /* 1. Set Bit 3 (0-indexed, 4th bit from the right) */
    reg |= (1U << 3);
    printf("After setting bit 3:         ");
    print_binary8(reg);

    /* 2. Set Bit 5 */
    reg |= (1U << 5);
    printf("After setting bit 5:         ");
    print_binary8(reg);

    /* 3. Check if Bit 3 is set */
    if ((reg & (1U << 3)) != 0) {
        printf("Bit 3 is confirmed SET\n");
    } else {
        printf("Bit 3 is CLEAR\n");
    }

    /* 4. Toggle Bit 5 (turn it off) */
    reg ^= (1U << 5);
    printf("After toggling bit 5:        ");
    print_binary8(reg);

    /* 5. Clear Bit 3 */
    reg &= ~(1U << 3);
    printf("After clearing bit 3:        ");
    print_binary8(reg);

    /* 6. Verify if Bit 3 is clear */
    if ((reg & (1U << 3)) == 0) {
        printf("Bit 3 is confirmed CLEAR\n");
    }

    return 0;
}

codeExample2.code:
#include <stdio.h>
#include <stdint.h>

/* 
 * Packs 24-bit RGB888 (8 bits Red, 8 bits Green, 8 bits Blue) 
 * into a space-efficient 16-bit RGB565 representation (5 Red, 6 Green, 5 Blue).
 */
uint16_t pack_rgb565(uint8_t r, uint8_t g, uint8_t b) {
    /* Extract top bits by shifting down */
    uint16_t red_5   = (r >> 3) & 0x1F; /* Keep only 5 bits */
    uint16_t green_6 = (g >> 2) & 0x3F; /* Keep only 6 bits */
    uint16_t blue_5  = (b >> 3) & 0x1F; /* Keep only 5 bits */

    /* Shift components into their target slots and merge them using OR */
    return (red_5 << 11) | (green_6 << 5) | blue_5;
}

/* Unpacks RGB565 back into standard RGB888 format with scale estimation */
void unpack_rgb565(uint16_t rgb565, uint8_t *r, uint8_t *g, uint8_t *b) {
    /* Extract components using masks, then shift back to full 8-bit ranges */
    *r = ((rgb565 >> 11) & 0x1F) << 3;
    *g = ((rgb565 >> 5) & 0x3F) << 2;
    *b = (rgb565 & 0x1F) << 3;
}

int main(void) {
    /* Example input: Forest Green (Red: 34, Green: 139, Blue: 34) */
    uint8_t orig_r = 34;
    uint8_t orig_g = 139;
    uint8_t orig_b = 34;

    printf("Original RGB888: R=%d, G=%d, B=%d\n", orig_r, orig_g, orig_b);

    uint16_t packed = pack_rgb565(orig_r, orig_g, orig_b);
    printf("Packed RGB565 (Hexadecimal): 0x%04X (16-bit storage)\n", packed);

    uint8_t unpacked_r, unpacked_g, unpacked_b;
    unpack_rgb565(packed, &unpacked_r, &unpacked_g, &unpacked_b);
    printf("Unpacked RGB888: R=%d, G=%d, B=%d (Slight precision loss is normal)\n", 
            unpacked_r, unpacked_g, unpacked_b);

    return 0;
}

